changeSet.sql:
ALTER TABLE user_project
    DROP COLUMN project_language;

ALTER TABLE project_file
    DROP COLUMN file_language;

ALTER TABLE project_file
    ADD COLUMN code_language_id BIGINT NOT NULL;

ALTER TABLE project_file
    ADD CONSTRAINT fk_project_file_code_language
        FOREIGN KEY (code_language_id)
            REFERENCES code_languages(id);

ALTER TABLE user_project
    ADD COLUMN code_language_id BIGINT NOT NULL;

ALTER TABLE user_project
    ADD CONSTRAINT fk_user_project_code_language
        FOREIGN KEY (code_language_id)
            REFERENCES code_languages(id);
